class MKAverage {
public:
    MKAverage(int m, int k) {
        this->m = m;
        this->k = k;
        this->stream = new int[m];
        this->count = 0;
        this->minHeap = new priority_queue<int>();
        this->maxHeap = new priority_queue<int>();
    }

    void addElement(int num) {
        if (count < m) {
            stream[count] = num;
            count++;
        } else {
            stream[insertIndex] = num;
            insertIndex = (insertIndex + 1) % m;
            if (stream[insertIndex] < stream[0]) {
                maxHeap->push(stream[0]);
                minHeap->push(stream[insertIndex]);
                stream[0] = stream[insertIndex];
                heapify(stream, 0, m);
            }
        }
    }

    int calculateMKAverage() {
        if (count < m) return -1;
        int sum = 0;
        for (int i = k; i < m - k; i++) {
            sum += stream[i];
        }
        return sum / (m - 2 * k);
    }
private:
    int m, k;
    int count;
    int insertIndex = 0;
    int* stream;
    priority_queue<int>* minHeap;
    priority_queue<int>* maxHeap;
    void heapify(int* arr, int i, int n) {
        int smallest = i;
        int left = 2 * i + 1;
        int right = 2 * i + 2;
        if (left < n && arr[left] < arr[smallest]) smallest = left;
        if (right < n && arr[right] < arr[smallest]) smallest = right;
        if (smallest != i) {
            swap(arr[i], arr[smallest]);
            heapify(arr, smallest, n);
        }
    }
};
```

